import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Validate input length to prevent buffer overflow
        if (input.length() > 10) {
            System.out.println("Input string exceeds buffer size limit.");
            return;
        }

        // Use StringBuilder to dynamically allocate memory
        StringBuilder buffer = new StringBuilder();
        buffer.append(input);

        System.out.println("Buffer contents: " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
